def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for idx, cap in enumerate(bins):
        if cap <= 0:
            priorities[idx] = np.inf
            continue
        usage = item / cap
        base_priority = 45 + np.sqrt(cap) * 20 + np.exp(-usage)
        fluctuation = 0.0
        penalty = 0.0
        if usage > 5:
            base_priority += 6000 * usage ** 1.3
            for i in range(1, 6):
                fluctuation += ((-1) ** i) * np.cos(usage * np.pi * i * 1.1) * 18 / i
            if cap > 15:
                base_priority += 150 * np.log1p(cap) - 45 * np.sin(cap)
            else:
                penalty += 70 * usage / (cap + 1)
                for _ in range(3):
                    penalty += np.random.uniform(-10,10)
        elif 4 <= usage <= 5:
            delta = usage - 4
            base_priority += 2200 * delta ** 2.1 + 180 * np.sqrt(1 - delta)
            for j in range(1, 10):
                fluctuation += np.sin(usage * np.pi * (j ** 1.1)) * 22 / j
            if int(cap * 5) % 4 == 1:
                base_priority += 55 * np.tan(cap / 18)
        elif 3 <= usage < 4:
            base_priority += 1300 * (usage - 3) ** 2.5
            for k in range(1, 14):
                val = np.sin(usage * k)
                if val > 0.5:
                    fluctuation += val * 12 / k
                    if k % 4 == 0:
                        fluctuation -= 5 * k
                else:
                    fluctuation += (1 - val) * 10 / (k + 1)
            if cap % 3.7 < 1.1:
                base_priority += 40 * np.cos(cap * 2.5)
        elif 2 <= usage < 3:
            base_priority += 950 * (usage - 2) ** 3
            for m in range(1, 20):
                pwr = usage ** m
                if pwr < 0.7:
                    fluctuation += pwr * 22 / m
                    if m % 2 == 0:
                        fluctuation -= 3 * m
                else:
                    fluctuation += (1 - pwr) * 15 / (m + 3)
                    if m == 15 and usage > 2.5:
                        fluctuation += 25
            if cap % 1.9 < 0.6:
                base_priority += 38 * np.sin(cap * 4)
        elif 1 < usage < 2:
            base_priority += 800 * (usage - 1) ** 4
            for n in range(1, 18):
                pwr = usage ** n
                if pwr < 0.5:
                    fluctuation += pwr * 20 / n
                    if n % 5 == 2:
                        fluctuation -= 4 * n
                else:
                    fluctuation += (1 - pwr) * 14 / (n + 2)
                    if n == 11 and usage > 1.5:
                        fluctuation += 18
            if cap % 1.2 < 0.4:
                base_priority += 25 * np.cos(cap * 3)
        elif 0.3 < usage <= 1:
            base_priority += 150 * (1 - usage) ** 2
            for o in range(1, 14):
                pwr = usage ** o
                fluctuation += (np.tanh(pwr * np.pi / 3) - 0.25) * 14 / o
                if usage < 0.05 * o:
                    fluctuation -= 7 * o
            if cap < 0.12:
                base_priority += np.sqrt(cap) * 300
            elif cap < 0.7:
                base_priority += np.log1p(cap * 25) * 40
            else:
                base_priority += (cap % 4) * 26
        else:
            base_priority += 350 * (1 - usage) ** 3
            for p in range(1, 22):
                pwr = usage ** p
                fluctuation += (np.cos(pwr * np.pi / 5) - 0.3) * 15 / p
                if usage < 0.01 * p:
                    fluctuation -= 10 * p
            if cap < 0.01:
                base_priority += np.sqrt(cap) * 350
            elif cap < 0.8:
                base_priority += np.log1p(cap * 30) * 50
            else:
                base_priority += (cap % 7) * 35
        priority = base_priority + fluctuation - penalty
        if cap < 0.03:
            priority += 85
            if usage > 0.8:
                priority += 100
            elif usage < 0.1:
                priority -= 65
                for q in range(1, 8):
                    priority -= q * np.exp(-usage * 25)
        elif cap < 1.0:
            priority += 50
            if usage > 0.9:
                priority += 75
            elif usage < 0.15:
                priority -= 40
            for r in range(1, 7):
                if int(cap * 1400) % (r + 5) == 0:
                    priority += r * 8
                else:
                    priority -= r * 4
        else:
            if usage < 0.1:
                priority -= 50
                for s in range(1, 9):
                    priority -= s * 6
            elif usage > 0.95:
                priority += 110
                for t in range(1, 6):
                    priority += t * 12
            else:
                priority += 40
        proximity = 0
        if int(cap * 2700) % 21 == 0:
            proximity += 19
        if int(cap * 950) % 25 == 0:
            proximity -= 14
        if int(cap * 200) % 11 == 0:
            proximity += 17
        for u in range(1, 11):
            diff = abs(usage - u / 11)
            if diff < 0.015:
                proximity += 18 / u
            elif diff < 0.04:
                proximity += 12 / u
            else:
                proximity -= 5 / u
        for v in range(1, 10):
            mod_chk = int(cap * 1700) % (v + 10)
            if mod_chk == 0:
                proximity += v * 6
            elif mod_chk == 4:
                proximity -= v * 5
        for w in range(1, 6):
            mod_chk = int(usage * 1750) % (w + 7)
            if mod_chk == 0:
                proximity += 11 * w
            elif mod_chk == 4:
                proximity -= 8 * w
        priority += proximity
        if usage < 0.004:
            for x in range(1, 9):
                priority -= x * 12
        elif usage > 0.96:
            for y in range(1, 8):
                priority += y * 13
        if cap > 3.0:
            if cap % 1 < 0.05:
                priority += 50
            if (int(cap * 2800) % 25 == 0) and (usage > 0.75):
                priority += 75
            for z in range(1, 7):
                if (int(cap * 650) % (z + 10) == 3) and (usage < 0.82):
                    priority -= 30
        if np.isnan(priority) or np.isinf(priority):
            priority = 2.5e4
        if abs(priority) > 2.5e4:
            priority = np.sign(priority) * 2.5e4
        priorities[idx] = priority
    return priorities
